def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(1, 5):
                for b in range(1, 5):
                    part1 = ((ratio - 7) ** (a+b)) / (a*b + 1)
                    part2 = np.sin(ratio * b / (a + 0.5)) * np.cos(ratio * a / (b + 0.5))
                    priority += part1 * part2 * (a - b) ** 2
            priority += (np.exp(ratio - 7.5) * np.sin(ratio * 1.3)) ** 2
        elif 5 < ratio <= 8:
            accum = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    factor = ((ratio - p) ** 4) * np.tanh(ratio * q) / (q + 0.7)
                    acc_term = np.sin(ratio * p * q) * factor
                    accum += acc_term / (p + q)
            priority = accum + np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
        elif 3 <= ratio <= 5:
            total = 0
            for r in range(1, 15):
                term = ((ratio - 3) ** r) / (r * 2.0) * np.cos(r * ratio * 0.8)
                total += term
            priority = (total * np.cos(6 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
        elif 1 <= ratio < 3:
            s1 = 0
            s2 = 0
            for n in range(1, 12):
                s1 += ((3 - ratio) ** n) / (n ** 2 + 1)
            for m in range(1, 7):
                s2 += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 1)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s1 + s2 + penalty + np.exp(-2 / (ratio + 0.1))
        elif 0.5 <= ratio < 1:
            accum = 0
            for k in range(1, 20):
                accum += ((1 - ratio) ** k) / (k * 3.5) * np.cos(k * ratio * 3)
            priority = accum
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 18):
                s += ((0.5 - ratio) ** l) / (l * 5) * np.cos(l * ratio * 2.5)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 13):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.0)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if (i * item) % 3 == 0:
            for z in range(1, 5):
                priority += np.sin(ratio * z * i) / (z + 1)
        else:
            for z in range(1, 3):
                priority -= np.cos(ratio * z * i) / (z + 0.5)
        priorities[i] = priority
    return priorities
